// Build the prompt for the LLM based on job type
const input = $input.first().json;
const job = input.job;
const content = input.content;
const context = input.context || {};

const SYSTEM_PROMPT = `You are the AI Brain for Aaron's Life Operating System. You process personal knowledge management content and return structured JSON only.

CONTEXT:
- 8 life domains: faith, family, business, consulting, work, health, home, personal
- Task format: - [ ] Description [area:: X] [priority:: A/B/C] [due:: YYYY-MM-DD]
- Priority A = needle-mover (advances North Star quarterly rocks or annual goals)
- Priority B = important but not a needle-mover
- Priority C = nice-to-have

NEEDLE-MOVER DEFINITION:
A needle-mover directly advances one of Aaron's quarterly rocks or annual goals. Urgent != important. "Reply to Slack" is not a needle-mover. "Draft Echelon Seven offer page" is.

RULES:
- Return valid JSON only. No markdown fences. No explanatory text. Just the JSON object.
- Be concise. Summaries are 3-4 sentences max.
- Rewrite raw shorthand into clear, complete sentences that future-Aaron can understand in 2 weeks.
- When content crosses domains (e.g., "pray about consulting deal"), tag the primary area and list secondary in connections array.
- If uncertain about area, default to personal. If uncertain about priority, default to B.`;

const JOB_PROMPTS = {
  classify: `TASK: Classify this brain dump content into structured items.\n\nFor each item found, determine its type:\n- "task" — an actionable to-do with a clear completion state\n- "note" — information, thought, or reference to file away\n- "article" — a URL or article reference to read/summarize later\n- "decision" — something requiring deliberation with pros/cons (always Priority A)\n\nReturn JSON:\n{"results": [{"type": "task|note|article|decision", "title": "string", "content": "string", "area": "string", "priority": "A|B|C", "needle_mover": true|false, "due": "YYYY-MM-DD|null", "connections": ["area1", "area2"], "url": "string|null", "source_domain": "string"}]}`,

  summarize: `TASK: Summarize this article content.\n\nReturn JSON:\n{"results": {"title": "string", "summary": "3-4 sentence summary", "key_takeaways": ["takeaway1", "takeaway2", "takeaway3"], "area": "string", "needle_mover": true|false, "action_items": [{"task": "string", "area": "string", "priority": "A|B|C", "due": "YYYY-MM-DD|null"}]}}`,

  brief: `TASK: Generate a concise daily briefing (50-80 words max).\n\nYou will receive: overdue tasks, inbox count, and this week's needle-movers.\nReturn the top 3 focus items (needle-movers first), and one domain nudge if any life area has been neglected.\n\nReturn JSON:\n{"results": {"focus_items": ["item1", "item2", "item3"], "domain_nudge": "string|null", "overdue_count": 0}}`,

  triage: `TASK: Triage overdue tasks with actionable recommendations.\n\nFor each overdue task, recommend one of:\n- "escalate" — This is a needle-mover being ignored. Do it today.\n- "act" — Important, do it today.\n- "reschedule" — Push to a specific future date with reason.\n- "drop" — Stale, low-priority, not advancing any goal. Delete or move to someday/maybe.\n\nUse the North Star context to identify needle-movers.\n\nReturn JSON:\n{"results": [{"task": "string", "area": "string", "days_overdue": 0, "recommendation": "escalate|act|reschedule|drop", "reason": "string", "suggested_date": "YYYY-MM-DD|null"}]}`,

  review: `TASK: Generate a strategic weekly review.\n\nYou will receive: North Star goals, completed tasks this week, open needle-movers, and inbox items.\nAnalyze domain balance, needle-mover progress, and alignment between actions and stated goals.\n\nReturn JSON:\n{"results": {"needle_mover_scorecard": {"completed": [{"task": "string", "area": "string"}], "still_open": [{"task": "string", "area": "string", "next_action": "string"}], "completed_count": 0, "total_count": 0}, "domain_balance": {"faith": 0, "family": 0, "business": 0, "consulting": 0, "work": 0, "health": 0, "home": 0, "personal": 0}, "domain_warning": "string|null", "wins": ["string"], "next_week_focus": ["string", "string", "string"], "honest_question": "string"}}`
};

const jobPrompt = JOB_PROMPTS[job];
if (!jobPrompt) {
  return [{ json: { success: false, error: `Unknown job type: ${job}` } }];
}

let userMessage = jobPrompt + '\n\nCONTENT:\n' + content;

if (context.north_star) {
  userMessage += '\n\nNORTH STAR GOALS:\n' + context.north_star;
}
if (context.overdue_tasks) {
  userMessage += '\n\nOVERDUE TASKS:\n' + context.overdue_tasks;
}
if (context.weekly_completions) {
  userMessage += '\n\nCOMPLETED THIS WEEK:\n' + context.weekly_completions;
}
if (context.open_needle_movers) {
  userMessage += '\n\nOPEN NEEDLE-MOVERS:\n' + context.open_needle_movers;
}

return [{
  json: {
    systemPrompt: SYSTEM_PROMPT,
    userMessage: userMessage,
    job: job
  }
}];

// Parse Groq response
const input = $input.first().json;
try {
  const content = input.choices[0].message.content;
  const parsed = JSON.parse(content);
  return [{ json: { success: true, ...parsed, source: 'groq' } }];
} catch (e) {
  return [{ json: { success: false, error: 'Failed to parse Groq response: ' + e.message, raw: JSON.stringify(input) } }];
}

// Parse Gemini response
const input = $input.first().json;
try {
  let text;
  if (input.candidates && input.candidates[0]) {
    text = input.candidates[0].content.parts[0].text;
  } else {
    return [{ json: { success: false, error: 'No Gemini response', raw: JSON.stringify(input) } }];
  }
  // Strip markdown fences if present
  text = text.replace(/^```json\n?/i, '').replace(/\n?```$/i, '').trim();
  const parsed = JSON.parse(text);
  return [{ json: { success: true, ...parsed, source: 'gemini' } }];
} catch (e) {
  return [{ json: { success: false, error: 'Failed to parse Gemini response: ' + e.message, raw: JSON.stringify(input) } }];
}

// Merge point — return whichever response we got
const input = $input.first().json;
return [{ json: input }];
